#ifndef TANKFILL_FSM_H_
#define TANKFILL_FSM_H_

//===================================================================================================================
// Tank Fill State Machine declarations.
//===================================================================================================================
/* 
 * Macro is intended to be used in the customization functions for dispatching events to the state machine.
 * This macro should be used instead of the TankFillEvent() function due to the Key Statements
 *     state variable =
 * and
 *     developer variables =
 * These Key Statements directly affect the function arguments of the customization functions and using the macro
 * DISPATCH_FSM_EVENT(event) will abstract the function arguments, allowing the developer to not have to modify code when the
 * Key Statements are removed/added to the PlantUML text.
 *
 * @param event = TANKFILL_FSM_EVENT_TYPE
 */
#define DISPATCH_FSM_EVENT(event)\
    TankFillFsmEvent(event, fsm_var)

/*
 * Macro is used to define the function arguments to the state machine customization functions.
 * The arguments are defined as a macro to abstract the state machine variables and developer variables
 * from the customization functions headers added to the module.c file.  This was done to prevent duplicate
 * customization functions from being defined in the module.c file when the developer adds or modifies the
 * Key Statements state variable = OR developer variables =.
 */
#define FSM_CUSTOMIZATION_FUNCTION_ARGUMENT\
    TANKFILL_FSM_VAR_TYPE * fsm_var /* DO NOT USE, used by the auto-generated code for controlling execution of the state machine */

/*
 * Macro is used to define the function arguments to the state machine guard functions.
 * The arguments are defined as a macro to abstract the developer variables. This was
 * done to prevent duplicate guard functions from being defined in the module.c file
 * when the developer adds or modifies the Key Statement
 *     developer variables =.
 */
#define FSM_GUARD_FUNCTION_ARGUMENT\
    void

// TankFill state machine states
typedef enum
{
    FSM_STATE_NONE,
    FSM_STATE_INITIALIZE, // PlantUML diagram state INITIALIZE
    FSM_STATE_FILL_WATER, // PlantUML diagram state FILL_WATER
    FSM_STATE_FILL_COMPLETE, // PlantUML diagram state FILL_COMPLETE
    FSM_STATE_NO_WATER, // PlantUML diagram state NO_WATER
    FSM_STATE_TANK_FILL_DELAY, // PlantUML diagram state TANK_FILL_DELAY
    FSM_STATE_AFTER_FILL_CHECK_SUBCYCLE, // PlantUML diagram state AFTER_FILL_CHECK_SUBCYCLE
    NUM_OF_STATES
} TANKFILL_FSM_STATE_TYPE;

// declaration of the structure that will be passed as a function argument to the state machine auto generated functions
typedef struct
{
    TANKFILL_FSM_STATE_TYPE State; // the current state of the state machine
    BOOL_TYPE Transition; // TRUE event triggered a state transition else FALSE
} TANKFILL_FSM_VAR_TYPE;

// Tank Fill State Machine state machine events
typedef enum
{
    // private events
    FSM_EVENT_AFTERFILLWATERCHECKNEEDED = 1, // PlantUML diagram event AfterFillWaterCheckNeeded
    FSM_EVENT_FILLCOMPLETED, // PlantUML diagram event FillCompleted
    FSM_EVENT_NOWATERDETECTED, // PlantUML diagram event NoWaterDetected
    FSM_EVENT_RESTARTFILL, // PlantUML diagram event RestartFill
    FSM_EVENT_STARTTANKFILL, // PlantUML diagram event StartTankFill
    FSM_EVENT_WATERFILLOVER // PlantUML diagram event WaterFillOver
} TANKFILL_FSM_EVENT_TYPE;

// Tank Fill State Machine state machine control functions
static void TankFillFsmInitialize(TANKFILL_FSM_STATE_TYPE * state);
static void TankFillFsmExecute(TANKFILL_FSM_STATE_TYPE * state);
static void TankFillFsmEvent(TANKFILL_FSM_EVENT_TYPE event, TANKFILL_FSM_VAR_TYPE * fsm_var);
static TANKFILL_FSM_VAR_TYPE TankFillBuildFsmVar(TANKFILL_FSM_STATE_TYPE state);

// Tank Fill State Machine state machine customization function prototypes
static void FillWater(FSM_CUSTOMIZATION_FUNCTION_ARGUMENT);
static void FillWaterInitialCheck(FSM_CUSTOMIZATION_FUNCTION_ARGUMENT);
static void InitializeTankFillVariables(FSM_CUSTOMIZATION_FUNCTION_ARGUMENT);
static void ResetAFSubcycleExecution(FSM_CUSTOMIZATION_FUNCTION_ARGUMENT);
static void SetH2OAlarm(FSM_CUSTOMIZATION_FUNCTION_ARGUMENT);
static void StartDelayTimer(FSM_CUSTOMIZATION_FUNCTION_ARGUMENT);
static void UpdateStatistics(FSM_CUSTOMIZATION_FUNCTION_ARGUMENT);
static void WaitAFSubcycleExecution(FSM_CUSTOMIZATION_FUNCTION_ARGUMENT);
static void WaitForPauseEnd(FSM_CUSTOMIZATION_FUNCTION_ARGUMENT);
static void WaitForTankFillDelay(FSM_CUSTOMIZATION_FUNCTION_ARGUMENT);

//===================================================================================================================
// Tank Fill State Machine definitions.
//===================================================================================================================
/**
 * @brief Configures the TankFill state machine to start execution from the Pseudo Initial state.
 * @param state: pointer to the state machine state variable
 */
static void TankFillFsmInitialize(TANKFILL_FSM_STATE_TYPE * state)
{
    // define the initial state
    TANKFILL_FSM_VAR_TYPE fsm_var = TankFillBuildFsmVar(FSM_STATE_INITIALIZE);
    // state entry actions
    InitializeTankFillVariables(&fsm_var);
    *state = fsm_var.State;
}

/**
 * @brief Executes the TankFill state machine do actions.
 * @param state: pointer to the state machine state variable
 */
static void TankFillFsmExecute(TANKFILL_FSM_STATE_TYPE * state)
{
    TANKFILL_FSM_VAR_TYPE fsm_var = TankFillBuildFsmVar(*state);
    switch ( fsm_var.State )
    {
        default:
            // do nothing
            break;
        case FSM_STATE_FILL_WATER: // PlantUML diagram state FILL_WATER
            FillWater(&fsm_var);
            break;
        case FSM_STATE_NO_WATER: // PlantUML diagram state NO_WATER
            WaitForPauseEnd(&fsm_var);
            break;
        case FSM_STATE_TANK_FILL_DELAY: // PlantUML diagram state TANK_FILL_DELAY
            WaitForTankFillDelay(&fsm_var);
            break;
        case FSM_STATE_AFTER_FILL_CHECK_SUBCYCLE: // PlantUML diagram state AFTER_FILL_CHECK_SUBCYCLE
            WaitAFSubcycleExecution(&fsm_var);
            break;
    }
    *state = fsm_var.State;
}

/**
 * NOTE: The DISPATCH_FSM_EVENT(event) macro should be used instead of this function to dispatch events to the
 *       state machine to make maintaining and updating the state machine customization functions.
 *
 * @brief Dispatch the event to the TankFill state machine and consume it.
 * @param event: the event to dispatch to the state machine
 * @param state: pointer to the finite state machine variables
 */
static void TankFillFsmEvent(TANKFILL_FSM_EVENT_TYPE event, TANKFILL_FSM_VAR_TYPE * fsm_var)
{
    fsm_var->Transition = FALSE;
    switch ( event )
    {
        default:
            // do nothing
            break;
        case FSM_EVENT_AFTERFILLWATERCHECKNEEDED: // event AfterFillWaterCheckNeeded
            switch ( fsm_var->State ) // state from
            {
                default:
                    // do nothing
                    break;
                case FSM_STATE_TANK_FILL_DELAY: // state TANK_FILL_DELAY
                    {
                        // go to state AFTER_FILL_CHECK_SUBCYCLE
                        fsm_var->State = FSM_STATE_AFTER_FILL_CHECK_SUBCYCLE;
                        // state entry actions
                        ResetAFSubcycleExecution(fsm_var);
                        fsm_var->Transition = TRUE;
                    }
                    break;
            }
            break;
        case FSM_EVENT_FILLCOMPLETED: // event FillCompleted
            switch ( fsm_var->State ) // state from
            {
                default:
                    // do nothing
                    break;
                case FSM_STATE_INITIALIZE: // state INITIALIZE
                    {
                        // go to state FILL_COMPLETE
                        fsm_var->State = FSM_STATE_FILL_COMPLETE;
                        fsm_var->Transition = TRUE;
                    }
                    break;
                case FSM_STATE_TANK_FILL_DELAY: // state TANK_FILL_DELAY
                    {
                        // transition action
                        UpdateStatistics(fsm_var);
                        // go to state FILL_COMPLETE
                        fsm_var->State = FSM_STATE_FILL_COMPLETE;
                        fsm_var->Transition = TRUE;
                    }
                    break;
                case FSM_STATE_AFTER_FILL_CHECK_SUBCYCLE: // state AFTER_FILL_CHECK_SUBCYCLE
                    {
                        // transition action
                        UpdateStatistics(fsm_var);
                        // go to state FILL_COMPLETE
                        fsm_var->State = FSM_STATE_FILL_COMPLETE;
                        fsm_var->Transition = TRUE;
                    }
                    break;
            }
            break;
        case FSM_EVENT_NOWATERDETECTED: // event NoWaterDetected
            switch ( fsm_var->State ) // state from
            {
                default:
                    // do nothing
                    break;
                case FSM_STATE_FILL_WATER: // state FILL_WATER
                    {
                        // go to state NO_WATER
                        fsm_var->State = FSM_STATE_NO_WATER;
                        // state entry actions
                        SetH2OAlarm(fsm_var);
                        fsm_var->Transition = TRUE;
                    }
                    break;
            }
            break;
        case FSM_EVENT_RESTARTFILL: // event RestartFill
            switch ( fsm_var->State ) // state from
            {
                default:
                    // do nothing
                    break;
                case FSM_STATE_NO_WATER: // state NO_WATER
                    {
                        // go to state FILL_WATER
                        fsm_var->State = FSM_STATE_FILL_WATER;
                        // state entry actions
                        FillWaterInitialCheck(fsm_var);
                        fsm_var->Transition = TRUE;
                    }
                    break;
            }
            break;
        case FSM_EVENT_STARTTANKFILL: // event StartTankFill
            switch ( fsm_var->State ) // state from
            {
                default:
                    // do nothing
                    break;
                case FSM_STATE_INITIALIZE: // state INITIALIZE
                    {
                        // go to state FILL_WATER
                        fsm_var->State = FSM_STATE_FILL_WATER;
                        // state entry actions
                        FillWaterInitialCheck(fsm_var);
                        fsm_var->Transition = TRUE;
                    }
                    break;
            }
            break;
        case FSM_EVENT_WATERFILLOVER: // event WaterFillOver
            switch ( fsm_var->State ) // state from
            {
                default:
                    // do nothing
                    break;
                case FSM_STATE_FILL_WATER: // state FILL_WATER
                    {
                        // go to state TANK_FILL_DELAY
                        fsm_var->State = FSM_STATE_TANK_FILL_DELAY;
                        // state entry actions
                        StartDelayTimer(fsm_var);
                        fsm_var->Transition = TRUE;
                    }
                    break;
            }
            break;
    }
}

/**
 * @brief Define the TANKFILL_FSM_VAR_TYPE with the passed state argument
 * @param state = the current state of the state machine
 * @return = the TANKFILL_FSM_VAR_TYPE initialized with the state argument
 */
static TANKFILL_FSM_VAR_TYPE TankFillBuildFsmVar(TANKFILL_FSM_STATE_TYPE state)
{
    TANKFILL_FSM_VAR_TYPE fsm_var;
    fsm_var.State = state;
    fsm_var.Transition = FALSE;
    return ( fsm_var );
}



#endif /* TANKFILL_FSM_H_ */
